import{_ as i}from"./chunks/map-enhance-panel.DHHj-2hM.js";import{_ as o,a as r}from"./chunks/map-enhance-languages.CCjNPkem.js";import{_ as l,o as d,c as n,ag as t,j as e}from"./chunks/framework.DjqkqlVQ.js";const k=JSON.parse('{"title":"STS2 Map Enhance Mod","description":"","frontmatter":{},"headers":[],"relativePath":"mods/sts2-map-enhance/index.md","filePath":"mods/sts2-map-enhance/index.md","lastUpdated":1778341931000}'),s={name:"mods/sts2-map-enhance/index.md"};function h(c,a,p,m,f,_){return d(),n("div",null,[...a[0]||(a[0]=[t('<h1 id="sts2-map-enhance-mod" tabindex="-1">STS2 Map Enhance Mod <a class="header-anchor" href="#sts2-map-enhance-mod" aria-label="Permalink to &quot;STS2 Map Enhance Mod&quot;">​</a></h1><p>Map Enhance Mod 是一个面向 杀戮尖塔2 地图界面的可视化增强 Mod。它通过房间类型上色、路线分析、实时预览和快速开关，帮助玩家更快读懂地图、比较路线，并减少反复停下来辨认节点的成本。</p><p>当前版本：<code>0.6.2</code><br> 作者：Jason Song<br> 类型：地图可读性 / 路线规划 / UI 辅助<br> 是否影响玩法：否，主要改变地图信息呈现方式。</p><h2 id="截图" tabindex="-1">截图 <a class="header-anchor" href="#截图" aria-label="Permalink to &quot;截图&quot;">​</a></h2><div class="screenshot-grid"><figure><img src="'+i+'" alt="Map Enhance Mod 地图配置界面"><figcaption>路线分析与路线高亮。</figcaption></figure><figure><img src="'+o+'" alt="Map Enhance Mod 路线分析面板"><figcaption>地图配置与实时预览。</figcaption></figure><figure><img src="'+r+'" alt="Map Enhance Mod 多语言支持截图"><figcaption>多语言界面支持。</figcaption></figure></div><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><ul><li>按房间类型给地图节点上色。</li><li>在地图界面显示路线分析面板，汇总每条可行路线的关键节点数量。</li><li>鼠标悬停或点击路线条目时，高亮整条路线。</li><li>支持在游戏内调整每类房间的颜色、透明度和亮度。</li><li>设置页提供实时预览，不需要反复重启游戏看效果。</li><li>地图打开时可实时应用配置。</li><li>使用 <code>F8</code> 快速开启或关闭地图上色。</li><li>一键恢复推荐默认配色。</li></ul><h2 id="支持的房间类型" tabindex="-1">支持的房间类型 <a class="header-anchor" href="#支持的房间类型" aria-label="Permalink to &quot;支持的房间类型&quot;">​</a></h2><p>当前会处理这些地图节点：</p><table tabindex="0"><thead><tr><th>类型</th><th>作用</th></tr></thead><tbody><tr><td>Enemy</td><td>普通敌人</td></tr><tr><td>Elite</td><td>精英</td></tr><tr><td>Rest</td><td>休息点</td></tr><tr><td>Shop</td><td>商店</td></tr><tr><td>Treasure</td><td>宝箱</td></tr><tr><td>Unknown</td><td>未知房间</td></tr></tbody></table><p>Boss 和 Ancient / Special 节点目前保持原版表现，避免和原游戏的悬停、动画逻辑产生冲突。</p><h2 id="路线分析" tabindex="-1">路线分析 <a class="header-anchor" href="#路线分析" aria-label="Permalink to &quot;路线分析&quot;">​</a></h2><p>路线分析功能会基于游戏真实的地图图结构枚举当前合法的未来路线，而不是根据屏幕坐标猜测路径。它会在地图右下角显示路线列表，并提供轻量级评分和原因说明。</p><p>每条路线会汇总：</p><ul><li>精英数量</li><li>商店数量</li><li>休息点数量</li><li>未知房间数量</li><li>宝箱数量</li><li>普通怪数量</li></ul><p>评分会参考当前生命值、金币、商店时机、精英密度、休息点缓冲等因素。它不是“最优路线计算器”，更适合当作路线比较和风险提示工具。</p><h2 id="游戏内配置" tabindex="-1">游戏内配置 <a class="header-anchor" href="#游戏内配置" aria-label="Permalink to &quot;游戏内配置&quot;">​</a></h2><p>打开路径：</p><p><code>Settings -&gt; 地图配置 / Map Config</code></p><p>你可以在这里：</p><ul><li>开启或关闭地图上色。</li><li>开启或关闭图标染色。</li><li>调整每种房间类型的颜色。</li><li>调整透明度。</li><li>调整亮度。</li><li>立即预览配置效果。</li><li>恢复推荐默认配色。</li></ul><p>配置会自动保存，并在地图打开时自动应用。</p><h2 id="默认配色思路" tabindex="-1">默认配色思路 <a class="header-anchor" href="#默认配色思路" aria-label="Permalink to &quot;默认配色思路&quot;">​</a></h2><p>内置默认配色优先考虑“扫一眼就能分辨”：</p><table tabindex="0"><thead><tr><th>类型</th><th>默认识别方向</th></tr></thead><tbody><tr><td>Enemy</td><td>柔和低饱和钢色</td></tr><tr><td>Elite</td><td>深红色</td></tr><tr><td>Rest</td><td>火焰红</td></tr><tr><td>Shop</td><td>橄榄金</td></tr><tr><td>Treasure</td><td>金紫色</td></tr><tr><td>Unknown</td><td>绿色</td></tr></tbody></table><p>这些只是推荐值，所有颜色都可以在游戏内自定义。</p><h2 id="安装说明" tabindex="-1">安装说明 <a class="header-anchor" href="#安装说明" aria-label="Permalink to &quot;安装说明&quot;">​</a></h2><p>发布包通常包含：</p><ul><li><code>sts2_map_mod.dll</code></li><li><code>sts2_map_mod.pck</code></li><li><code>sts2_map_mod.json</code></li><li><code>map_color_config.json.txt</code></li></ul><p>注意：不要把 <code>map_color_config.json</code> 直接放进游戏 Mod 文件夹。游戏可能会把所有 <code>*.json</code> 当作 Mod manifest 读取，所以配置文件使用 <code>map_color_config.json.txt</code>。</p><h2 id="视频演示" tabindex="-1">视频演示 <a class="header-anchor" href="#视频演示" aria-label="Permalink to &quot;视频演示&quot;">​</a></h2><p>【杀戮尖塔2】地图增强模组</p>',32),e("div",{class:"video-embed"},[e("iframe",{src:"https://player.bilibili.com/player.html?bvid=BV1XfDSBXEKk&page=1",title:"【杀戮尖塔2】地图增强模组",scrolling:"no",border:"0",frameborder:"no",framespacing:"0",allowfullscreen:"true"})],-1),t('<h2 id="链接" tabindex="-1">链接 <a class="header-anchor" href="#链接" aria-label="Permalink to &quot;链接&quot;">​</a></h2><ul><li>GitHub: <a href="https://github.com/JasonSongHoho/sts2_map_mod" target="_blank" rel="noreferrer">JasonSongHoho/sts2_map_mod</a></li><li>夸克下载：<a href="https://pan.quark.cn/s/f2902ba27eff" target="_blank" rel="noreferrer">pan.quark.cn/s/f2902ba27eff</a></li><li>Nexus Mods: <a href="https://www.nexusmods.com/slaythespire2/mods/475" target="_blank" rel="noreferrer">杀戮尖塔2 Mod #475</a></li><li>视频演示：<a href="https://www.bilibili.com/video/BV1XfDSBXEKk" target="_blank" rel="noreferrer">Bilibili BV1XfDSBXEKk</a></li><li>鸣谢：<a href="/jasonsong-games/mods/sts2-map-enhance/credits">鸣谢</a></li><li>更新记录：<a href="/jasonsong-games/mods/sts2-map-enhance/changelog">Release Notes</a></li><li>问题反馈：<a href="/jasonsong-games/mods/sts2-map-enhance/support">反馈说明</a></li><li>赞赏支持：<a href="/jasonsong-games/support/">全站支持页</a></li></ul><h2 id="许可" tabindex="-1">许可 <a class="header-anchor" href="#许可" aria-label="Permalink to &quot;许可&quot;">​</a></h2><p>本项目仅允许非商业使用。个人使用、修改和分享是允许的；未经书面许可，不允许商业使用。</p>',4)])])}const q=l(s,[["render",h]]);export{k as __pageData,q as default};
